class Solution:
    def calcEquation(self, equations, values, queries):
        parent = {}
        weight = {}

        def find(x):
            if x not in parent:
                parent[x] = x
                weight[x] = 1.0
                return x
            if parent[x] != x:
                root = find(parent[x])
                weight[x] *= weight[parent[x]]
                parent[x] = root
            return parent[x]

        for (a, b), v in zip(equations, values):
            find(a)
            find(b)
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
                weight[ra] = v * weight[b] / weight[a]

        res = []
        for c, d in queries:
            if c not in parent or d not in parent or find(c) != find(d):
                res.append(-1.0)
            else:
                res.append(weight[c] / weight[d])
        return res

