var calcEquation = function(equations, values, queries) {
    const parent = {};
    const weight = {};
    function find(x) {
        if (!(x in parent)) {
            parent[x] = x;
            weight[x] = 1.0;
            return x;
        }
        if (parent[x] !== x) {
            const root = find(parent[x]);
            weight[x] *= weight[parent[x]];
            parent[x] = root;
        }
        return parent[x];
    }
    for (let i = 0; i < equations.length; i++) {
        const [a, b] = equations[i];
        const v = values[i];
        find(a);
        find(b);
        const ra = find(a), rb = find(b);
        if (ra !== rb) {
            parent[ra] = rb;
            weight[ra] = v * weight[b] / weight[a];
        }
    }
    const res = [];
    for (const [c, d] of queries) {
        if (!(c in parent) || !(d in parent) || find(c) !== find(d)) {
            res.push(-1.0);
        } else {
            res.push(weight[c] / weight[d]);
        }
    }
    return res;
};
